use aiken/collection/dict
use cardano/transaction.{OutputReference, Transaction}

pub type RegistryDatum {
  registry: dict.Dict<ByteArray, Int>,
  required_key: ByteArray,
  min_value: Int,
}

validator registry_lookup {
  spend(
    datum: Option<RegistryDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when dict.get(d.registry, d.required_key) is {
          None -> False
          Some(value) -> value >= d.min_value
        }
    }
  }
}

