pub type ScaleDatum {
  scores: dict.Dict<ByteArray, Int>,
  multiplier: Int,
  min_total: Int,
}

validator scaled_values {
  spend(
    datum: Option<ScaleDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let scaled =
          dict.map(d.scores, fn(_key, score) { score * d.multiplier })
        let total =
          dict.foldl(scaled, 0, fn(_key, value, acc) { acc + value })
        total >= d.min_total
      }
    }
  }
}

