pub type KeysDatum {
  registry: dict.Dict<ByteArray, Int>,
  signer: ByteArray,
}

validator keys_check {
  spend(datum: Option<KeysDatum>, _redeemer: Data, _ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let keys = dict.keys(d.registry)
        let signer_in_registry = list.has(keys, d.signer)
        let tx_signed = list.has(self.extra_signatories, d.signer)
        signer_in_registry && tx_signed
      }
    }
  }

  else(_) {
    fail
  }
}

