pub type FeeDatum {
  fee_table: dict.Dict<ByteArray, Int>,
  operation: ByteArray,
  default_fee: Int,
  max_allowed: Int,
}

fn resolve_fee(datum: FeeDatum) -> Int {
  when dict.get(datum.fee_table, datum.operation) is {
    Some(fee) -> fee
    None -> datum.default_fee
  }
}

validator default_fee_validator {
  spend(
    datum: Option<FeeDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(fd) -> {
        let fee = resolve_fee(fd)
        fee <= fd.max_allowed
      }
    }
  }

  else(_) {
    fail
  }
}

