pub type TokenDatum {
  policy_id: ByteArray,
  min_token_types: Int,
}

validator token_count_gate {
  spend(
    datum: Option<TokenDatum>,
    _redeemer: Data,
    ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let own_input =
          list.find(self.inputs, fn(input) { input.output_reference == ref })
        when own_input is {
          None -> False
          Some(input) -> {
            let own_address = input.output.address
            let continuing_outputs =
              list.filter(
                self.outputs,
                fn(output) { output.address == own_address },
              )
            list.any(
              continuing_outputs,
              fn(output) {
                let token_dict = assets.tokens(output.value, d.policy_id)
                dict.size(token_dict) >= d.min_token_types
              },
            )
          }
        }
      }
    }
  }

  else(_) {
    False
  }
}

