pub type MintRedeemer {
  Mint
  Burn
}

validator multi_asset_mint {
  mint(redeemer: MintRedeemer, policy_id: ByteArray, self: Transaction) -> Bool {
    let minted_tokens = assets.tokens(self.mint, policy_id)
    let token_pairs = dict.to_pairs(minted_tokens)

    when redeemer is {
      Mint -> {
        let has_tokens = !dict.is_empty(minted_tokens)
        let all_quantity_one =
          list.all(token_pairs, fn(pair) { pair.2nd == 1 })
        has_tokens && all_quantity_one
      }
      Burn -> {
        let has_tokens = !dict.is_empty(minted_tokens)
        let all_quantity_neg_one =
          list.all(token_pairs, fn(pair) { pair.2nd == -1 })
        has_tokens && all_quantity_neg_one
      }
    }
  }

  else(_) {
    fail
  }
}

