pub type RemovalDatum {
  registry: dict.Dict<ByteArray, Int>,
  remove_key: ByteArray,
  owner: ByteArray,
}

validator entry_removal {
  spend(
    datum: Option<RemovalDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let owner_signed =
          list.has(self.extra_signatories, d.owner)

        let updated_registry = dict.delete(d.registry, d.remove_key)

        let key_removed = !dict.has_key(updated_registry, d.remove_key)

        owner_signed && key_removed
      }
    }
  }
}

